a.xlink:href:
# entity_pool.gd
extends Node


var pools: Dictionary = {}  # scene_path -> Array of instances


func get_entity(scene_path: String) -> Node3D:
    if pools.has(scene_path) and pools[scene_path].size() > 0:
        var instance = pools[scene_path].pop_back()
        instance.show()
        return instance
    else:
        return load(scene_path).instantiate()


func return_entity(entity: Node3D, scene_path: String):
    entity.hide()
    entity.position = Vector3.ZERO
    # reset all components via signals
    entity.reset.emit()
    if not pools.has(scene_path):
        pools[scene_path] = []
    pools[scene_path].append(entity)

div.div:
# entity_pool.gd


extends Node






var pools: Dictionary = {}  # scene_path -> Array of instances






func get_entity(scene_path: String) -> Node3D:


if pools.has(scene_path) and pools[scene_path].size() > 0:


var instance = pools[scene_path].pop_back()


instance.show()


return instance


else:


return load(scene_path).instantiate()






func return_entity(entity: Node3D, scene_path: String):


entity.hide()


entity.position = Vector3.ZERO


# reset all components via signals


entity.reset.emit()


if not pools.has(scene_path):


pools[scene_path] = []


pools[scene_path].append(entity)

